function shortestBridge(grid) {
    const n = grid.length;
    const q = [];

    loop:
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < n; j++) {
            if (grid[i][j] === 1) {
                dfs(grid, q, i, j);
                break loop;
            }
        }
    }

    let steps = 0;
    const directions = [[1, 0], [-1, 0], [0, 1], [0, -1]];

    while (q.length) {
        const size = q.length;
        for (let i = 0; i < size; i++) {
            const [x, y] = q.shift();
            for (const [dx, dy] of directions) {
                const nx = x + dx, ny = y + dy;
                if (nx >= 0 && nx < n && ny >= 0 && ny < n && grid[nx][ny] !== 2) {
                    if (grid[nx][ny] === 1) return steps;
                    grid[nx][ny] = 2;
                    q.push([nx, ny]);
                }
            }
        }
        steps++;
    }

    return -1;
}

function dfs(grid, q, i, j) {
    const n = grid.length;
    if (i < 0 || i >= n || j < 0 || j >= n || grid[i][j] !== 1) return;
    grid[i][j] = 2;
    q.push([i, j]);

    dfs(grid, q, i - 1, j);
    dfs(grid, q, i + 1, j);
    dfs(grid, q, i, j - 1);
    dfs(grid, q, i, j + 1);
}
```


    1. Find the first 1 in the matrix, which belongs to one of the islands.
2. Perform a depth-first search (DFS) starting from this cell to find all connected 1's in this island and set them to a temporary value (e.g., -1 for Python or 2 for C++ and JavaScript) to indicate they have been visited. Store these cells in a queue.
3. Initiate a breadth-first search (BFS) from the cells in the queue, trying to find the other island cells (containing a 1). Keep track of the number of steps taken during the BFS.
4. If a 1 is found during the BFS, return the number of steps. If the BFS is finished and no 1 is found, the islands are connected, and there are no cells to flip.

The time complexity of this solution is O(n^2), as both DFS and BFS run in O(n^2) time in the worst case.

